from starlette.middleware import Middleware
from starlette.middleware.base import BaseHTTPMiddleware
from starlette.requests import Request
from starlette.responses import Response
from collections import defaultdict
import time

class QueryDepthLimiter:
    def __init__(self, max_depth: int = 10):
        self.max_depth = max_depth
    
    def check_depth(self, info):
        def get_depth(field, current_depth=0):
            if current_depth > self.max_depth:
                raise Exception(f"Query depth limit exceeded: {self.max_depth}")
            if not field.selection_set:
                return current_depth
            max_child_depth = 0
            for selection in field.selection_set.selections:
                max_child_depth = max(max_child_depth, get_depth(selection, current_depth + 1))
            return max_child_depth
        
        return get_depth(info.field_nodes[0])

